import anthropic, json
from typing import Callable, Awaitable

client = anthropic.AsyncAnthropic()

# Session-level bypass cache: {session_id: {tool_name: True}}
_bypass_cache: dict[str, set[str]] = {}

async def run_agent_with_gates(
    task:          str,
    tools:         list[dict],
    tool_fns:      dict[str, Callable[..., Awaitable[Any]]],
    notify:        Callable[[ConfirmationRequest], Awaitable[None]],
    session_id:    str | None = None,
    max_steps:     int = 50,
) -> str:
    session_id = session_id or str(uuid.uuid4())
    _bypass_cache.setdefault(session_id, set())
    messages = [{"role": "user", "content": task}]

    for step in range(max_steps):
        response = await client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if hasattr(b, "text")), "")

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue

            gate = GATE_REGISTRY.get(block.name)
            needs_confirm = (
                gate is not None
                and not _should_bypass(gate, session_id)
            )

            if needs_confirm:
                req = create_request(gate, block.input, session_id)
                await notify(req)
                confirmed = await _wait_for_confirmation(req, gate.timeout_secs)

                if not confirmed:
                    result = json.dumps({
                        "error": f"Action '{block.name}' was not confirmed by the user."
                    })
                    tool_results.append({
                        "type": "tool_result", "tool_use_id": block.id,
                        "content": result, "is_error": True,
                    })
                    continue

                # Update bypass cache for ONCE_PER_SESSION gates
                if gate.bypass == BypassPolicy.ONCE_PER_SESSION:
                    _bypass_cache[session_id].add(block.name)

                # Apply grace period before executing
                if gate.grace_secs > 0:
                    cancelled = await _apply_grace_period(req, gate.grace_secs, notify)
                    if cancelled:
                        result = json.dumps({"error": "Action cancelled during grace period."})
                        tool_results.append({
                            "type": "tool_result", "tool_use_id": block.id,
                            "content": result, "is_error": True,
                        })
                        continue

            # Execute the tool
            fn = tool_fns.get(block.name)
            if fn is None:
                result = json.dumps({"error": f"unknown tool: {block.name}"})
            else:
                try:
                    res = await fn(**block.input)
                    result = json.dumps(res) if not isinstance(res, str) else res
                except Exception as exc:
                    result = json.dumps({"error": str(exc)})

            tool_results.append({
                "type": "tool_result", "tool_use_id": block.id, "content": result
            })

        messages.append({"role": "user", "content": tool_results})

    raise RuntimeError(f"Agent exceeded max_steps={max_steps}")

def _should_bypass(gate: GateDefinition, session_id: str) -> bool:
    if gate.bypass == BypassPolicy.ALWAYS:
        return True
    if gate.bypass == BypassPolicy.ONCE_PER_SESSION:
        return gate.tool_name in _bypass_cache.get(session_id, set())
    return False   # NEVER

async def _wait_for_confirmation(req: ConfirmationRequest, timeout: float) -> bool:
    try:
        await asyncio.wait_for(req.event.wait(), timeout=timeout)
        return req.confirmed is True
    except asyncio.TimeoutError:
        req.confirmed = False
        return False

from fastapi import FastAPI
from fastapi.responses import JSONResponse
app = FastAPI()

@app.get("/confirmations/{request_id}")
async def get_confirmation(request_id: str):
    req = _pending.get(request_id)
    if not req:
        return JSONResponse({"error": "not found"}, status_code=404)
    return JSONResponse({
        "request_id":  req.request_id,
        "tool_name":   req.tool_name,
        "prompt":      req.prompt,
        "risk":        req.risk,
        "description": req.description,
        "grace_secs":  req.grace_secs,
        "tool_input":  req.tool_input,
        "created_at":  req.created_at,
        "status":      "pending" if req.confirmed is None else ("confirmed" if req.confirmed else "denied"),
    })

@app.post("/confirmations/{request_id}/confirm")
async def confirm(request_id: str, confirmed_by: str = ""):
    req = _pending.get(request_id)
    if not req or req.confirmed is not None:
        return JSONResponse({"error": "not found or already decided"}, status_code=400)
    req.confirmed    = True
    req.confirmed_by = confirmed_by
    req.confirmed_at = datetime.datetime.utcnow().isoformat() + "Z"
    req.event.set()
    return JSONResponse({"status": "confirmed", "grace_secs": req.grace_secs})

@app.post("/confirmations/{request_id}/deny")
async def deny(request_id: str):
    req = _pending.get(request_id)
    if not req or req.confirmed is not None:
        return JSONResponse({"error": "not found or already decided"}, status_code=400)
    req.confirmed = False
    req.event.set()
    return JSONResponse({"status": "denied"})

@app.post("/confirmations/{request_id}/cancel-grace")
async def cancel_grace_endpoint(request_id: str):
    result = await cancel_during_grace(request_id)
    return JSONResponse(result)

import os

ENV = os.getenv("APP_ENV", "development")

def effective_bypass(gate: GateDefinition) -> BypassPolicy:
    """
    Override bypass policy per environment so developers are not
    blocked by confirmation gates during local iteration.
    """
    if ENV == "development":
        return BypassPolicy.ALWAYS         # no gates in dev
    if ENV == "staging":
        # In staging, ONCE_PER_SESSION; never bypass HIGH/CRITICAL
        if gate.risk in (RiskLevel.HIGH, RiskLevel.CRITICAL):
            return BypassPolicy.NEVER
        return BypassPolicy.ONCE_PER_SESSION
    return gate.bypass   # production: use the registry definition exactly

def effective_timeout(gate: GateDefinition) -> float:
    """Shorter timeouts in CI/automated testing."""
    if ENV in ("test", "ci"):
        return 5.0   # fail fast in automated runs
    return gate.timeout_secs
